  useEffect(() => {
    fetchProducts()
      .then(data => {
        setProducts(data);
        setIsLoading(false);
      })
      .catch(err => {
        setError(err.message);
        setIsLoading(false);
      });
  }, []);

  // Derived state in effect
  useEffect(() => {
    setFilteredProducts(
      products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()))
